import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';
import { LayoutComponent } from './shared/layout.component';

const ADMIN = { roles: ['admin'] as const };

/**
 * Storefront route tree. Hash routing is configured in app.config.ts.
 * Login/signup render standalone; everything else is wrapped by LayoutComponent.
 * The public catalog + product detail live inside the layout WITHOUT a guard.
 * Cart/checkout/orders require authGuard; admin/* additionally require roleGuard.
 * Each route carries `data.flow { node, edgesTo, ... }` for the flow map — every
 * navigable state is a real route (no state-only modals).
 */
export const routes: Routes = [
  {
    path: 'login',
    loadComponent: () => import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { node: 'login', entry: true, edgesTo: ['catalog', 'signup', 'admin-products'] } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { node: 'signup', edgesTo: ['catalog', 'login'] } },
  },
  {
    path: '',
    component: LayoutComponent,
    children: [
      // ---- Public browse ----
      {
        path: '',
        pathMatch: 'full',
        loadComponent: () => import('./pages/home/home.component').then((m) => m.HomeComponent),
        data: { flow: { node: 'catalog', showInNavbar: true, edgesTo: ['product-detail', 'cart'] } },
      },
      {
        path: 'products/:id',
        loadComponent: () =>
          import('./pages/product-detail/product-detail.component').then((m) => m.ProductDetailComponent),
        data: { flow: { node: 'product-detail', edgesTo: ['catalog', 'cart', 'login'] } },
      },

      // ---- Shopper (any logged-in user) ----
      {
        path: 'cart',
        canActivate: [authGuard],
        loadComponent: () => import('./pages/cart/cart.component').then((m) => m.CartComponent),
        data: { flow: { node: 'cart', showInNavbar: true, scope: 'shopper', edgesTo: ['checkout', 'catalog', 'product-detail'] } },
      },
      {
        path: 'checkout',
        canActivate: [authGuard],
        loadComponent: () => import('./pages/checkout/checkout.component').then((m) => m.CheckoutComponent),
        data: { flow: { node: 'checkout', scope: 'shopper', edgesTo: ['order-detail', 'cart'] } },
      },
      {
        path: 'orders',
        canActivate: [authGuard],
        loadComponent: () => import('./pages/orders/orders.component').then((m) => m.OrdersComponent),
        data: { flow: { node: 'orders', showInNavbar: true, scope: 'shopper', edgesTo: ['order-detail', 'catalog'] } },
      },
      {
        path: 'orders/:id',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/order-detail/order-detail.component').then((m) => m.OrderDetailComponent),
        data: { flow: { node: 'order-detail', scope: 'shopper', edgesTo: ['orders', 'product-detail'] } },
      },

      // ---- Admin ----
      {
        path: 'admin/products',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/admin-products/admin-products.component').then((m) => m.AdminProductsComponent),
        data: { roles: ADMIN.roles, flow: { node: 'admin-products', showInNavbar: true, scope: 'admin', edgesTo: ['admin-product-form', 'admin-orders'] } },
      },
      {
        path: 'admin/products/new',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/admin-product-form/admin-product-form.component').then((m) => m.AdminProductFormComponent),
        data: { roles: ADMIN.roles, flow: { node: 'admin-product-form', scope: 'admin', edgesTo: ['admin-products'] } },
      },
      {
        path: 'admin/products/:id',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/admin-product-form/admin-product-form.component').then((m) => m.AdminProductFormComponent),
        data: { roles: ADMIN.roles, flow: { node: 'admin-product-form', scope: 'admin', edgesTo: ['admin-products'] } },
      },
      {
        path: 'admin/orders',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/admin-orders/admin-orders.component').then((m) => m.AdminOrdersComponent),
        data: { roles: ADMIN.roles, flow: { node: 'admin-orders', showInNavbar: true, scope: 'admin', edgesTo: ['order-detail', 'admin-products'] } },
      },
      {
        path: 'admin/settings',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/admin-settings/admin-settings.component').then((m) => m.AdminSettingsComponent),
        data: { roles: ADMIN.roles, flow: { node: 'admin-settings', scope: 'admin', edgesTo: ['admin-products'] } },
      },
    ],
  },

  { path: '**', redirectTo: '' },
];
